import socket
import ipaddress
import urllib.parse
from typing import Set, Optional
import requests
from requests.adapters import HTTPAdapter
from urllib3.util.connection import create_connection


class SSRFProtectionAdapter(HTTPAdapter):
    def __init__(self, allowed_hosts: Set[str], *args, **kwargs):
        self.allowed_hosts = allowed_hosts
        super().__init__(*args, **kwargs)
        
    def send(self, request, *args, **kwargs):
        parsed = urllib.parse.urlparse(request.url)
        hostname = parsed.hostname
        
        if hostname not in self.allowed_hosts:
            raise ValueError(f"Host {hostname} is not in the allowlist")
        
        try:
            ip_addresses = socket.getaddrinfo(hostname, parsed.port or 80, socket.AF_UNSPEC, socket.SOCK_STREAM)
        except socket.gaierror:
            raise ValueError(f"Cannot resolve hostname {hostname}")
        
        for addr_info in ip_addresses:
            ip_str = addr_info[4][0]
            try:
                ip_obj = ipaddress.ip_address(ip_str)
                
                if ip_obj.is_loopback:
                    raise ValueError(f"Loopback address not allowed: {ip_str}")
                if ip_obj.is_link_local:
                    raise ValueError(f"Link-local address not allowed: {ip_str}")
                if ip_obj.is_multicast:
                    raise ValueError(f"Multicast address not allowed: {ip_str}")
                if ip_obj.is_private:
                    raise ValueError(f"Private address not allowed: {ip_str}")
                if isinstance(ip_obj, ipaddress.IPv4Address):
                    if ip_obj in ipaddress.IPv4Network('169.254.0.0/16'):
                        raise ValueError(f"AWS metadata address not allowed: {ip_str}")
                    if ip_obj in ipaddress.IPv4Network('0.0.0.0/8'):
                        raise ValueError(f"Reserved address not allowed: {ip_str}")
                if ip_obj.is_reserved:
                    raise ValueError(f"Reserved address not allowed: {ip_str}")
                    
            except ValueError as e:
                if "does not appear to be an IPv4 or IPv6 address" in str(e):
                    continue
                raise
        
        return super().send(request, *args, **kwargs)


def fetch_webhook_content(url: str, allowed_hosts: Optional[Set[str]] = None, timeout: int = 10) -> str:
    if allowed_hosts is None:
        allowed_hosts = {
            'api.stripe.com',
            'api.github.com',
            'hooks.slack.com',
            'api.twilio.com',
            'api.sendgrid.com',
        }
    
    parsed_url = urllib.parse.urlparse(url)
    
    if parsed_url.scheme not in ['http', 'https']:
        raise ValueError(f"Invalid URL scheme: {parsed_url.scheme}. Only http and https are allowed")
    
    if not parsed_url.hostname:
        raise ValueError("URL must contain a valid hostname")
    
    if parsed_url.hostname not in allowed_hosts:
        raise ValueError(f"Host {parsed_url.hostname} is not in the allowlist")
    
    session = requests.Session()
    session.mount('http://', SSRFProtectionAdapter(allowed_hosts))
    session.mount('https://', SSRFProtectionAdapter(allowed_hosts))
    
    try:
        response = session.get(
            url,
            timeout=timeout,
            allow_redirects=False,
            headers={'User-Agent': 'WebhookProcessor/1.0'}
        )
        
        if response.status_code in [301, 302, 303, 307, 308]:
            redirect_url = response.headers.get('Location')
            if redirect_url:
                redirect_parsed = urllib.parse.urlparse(redirect_url)
                if redirect_parsed.hostname not in allowed_hosts:
                    raise ValueError(f"Redirect to non-allowlisted host: {redirect_parsed.hostname}")
                
                response = session.get(
                    redirect_url,
                    timeout=timeout,
                    allow_redirects=False,
                    headers={'User-Agent': 'WebhookProcessor/1.0'}
                )
        
        response.raise_for_status()
        return response.text
        
    except requests.exceptions.RequestException as e:
        raise RuntimeError(f"Failed to fetch URL: {str(e)}")
    finally:
        session.close()


def add_allowed_host(allowed_hosts: Set[str], new_host: str) -> Set[str]:
    parsed = urllib.parse.urlparse(f"https://{new_host}")
    hostname = parsed.hostname or new_host
    allowed_hosts.add(hostname)
    return allowed_hosts


